mapper.select:
		/** UsptEvlTargetDao.select */
		select b.apply_id
  	      from uspt_sect a
	 		   inner join uspt_evl_trget b
					   on a.sect_id = b.sect_id
		 where a.evl_plan_id = #{evlPlanId}

/** UsptEvlTargetDao.selectList */ select a.receipt_no /*접수번호*/ , mem.member_nm /*회원명(사업자명)*/ , mem.charger_nm /*담당자명*/ , b.task_nm_ko /*과제명*/ , b.apply_realm_id /*지원분야id*/ , c.apply_realm_nm /*과제분야명*/ , a.apply_id /*신청id*/ , a.pblanc_id /*공고id*/ , a.rcept_odr /*접수차수*/ , row_number() over (order by a.created_dt desc) as rn from uspt_bsns_pblanc_applcnt a /*신청자*/ inner join uspt_bsns_pblanc_apply_task b /*신청과제*/ on a.apply_id = b.apply_id left outer join uspt_bsns_apply_realm c /*과제분야*/ on b.apply_realm_id = c.apply_realm_id left outer join cmmt_member mem on a.member_id = mem.member_id where 1 = 1 and a.pblanc_id = #{pblancId} /*공고ID는 필수*/ and a.apply_id not in ( select b.apply_id from uspt_sect a inner join uspt_evl_trget b on a.sect_id = b.sect_id where a.evl_plan_id = #{evlPlanId} ) /*해당 계획에 이미 등록된 신청자는 제외하고 조회함*/
and b.apply_realm_id = #{applyRealmId}
and mem.member_type = #{memberTypeCd}
and mem.charger_nm like '%' || #{chargerNm} || '%'
and mem.member_nm like '%' || #{memberNm} || '%'
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptEvlTargetDao.selectListCount */ select count(a.apply_id) as cnt from uspt_bsns_pblanc_applcnt a /*신청자*/ inner join uspt_bsns_pblanc_apply_task b /*신청과제*/ on a.apply_id = b.apply_id left outer join uspt_bsns_apply_realm c /*과제분야*/ on b.apply_realm_id = c.apply_realm_id left outer join cmmt_member mem on a.member_id = mem.member_id where 1 = 1 and a.pblanc_id = #{pblancId} /*공고ID는 필수*/ and a.apply_id not in ( select b.apply_id from uspt_sect a inner join uspt_evl_trget b on a.sect_id = b.sect_id where a.evl_plan_id = #{evlPlanId} ) /*해당 계획에 이미 등록된 신청자는 제외하고 조회함*/
and b.apply_realm_id = #{applyRealmId}
and mem.member_type = #{memberTypeCd}
and mem.charger_nm like '%' || #{chargerNm} || '%'
and mem.member_nm like '%' || #{memberNm} || '%'

/** UsptEvlTargetDao.selectListBySect */ select a.evl_plan_id , d.evl_trget_id , d.sect_id , d.evl_step_id , d.apply_id , e.receipt_no , e.member_nm , e.task_nm_ko , e.apply_realm_nm , row_number() over (order by e.created_dt desc) as rn from uspt_evl_plan a /*평가계획*/ inner join uspt_evl_step b /*평가단계*/ on a.evl_plan_id = b.evl_plan_id and b.sort_ordr_no = 1 /*평가단계의 첫번째 것으로만 join*/ inner join uspt_sect c /*평가분과*/ on a.evl_plan_id = c.evl_plan_id inner join uspt_evl_trget d /*평가대상*/ on b.evl_step_id = d.evl_step_id and c.sect_id = d.sect_id inner join (select a.receipt_no /*접수번호*/ , mem.member_nm /*회원명(사업자명)*/ , mem.charger_nm /*담당자명*/ , b.task_nm_ko /*과제명*/ , b.apply_realm_id /*지원분야id*/ , c.apply_realm_nm /*과제분야명*/ , a.apply_id /*신청id*/ , a.pblanc_id /*공고id*/ , a.rcept_odr /*접수차수*/ , a.created_dt from uspt_bsns_pblanc_applcnt a /*신청자*/ inner join uspt_bsns_pblanc_apply_task b /*신청과제*/ on a.apply_id = b.apply_id left outer join uspt_bsns_apply_realm c /*과제분야*/ on b.apply_realm_id = c.apply_realm_id left outer join cmmt_member mem /*회원정보*/ on a.member_id = mem.member_id) e /*평가대상 정보*/ on d.apply_id = e.apply_id where 1 = 1
and a.evl_plan_id = #{evlPlanId}
and c.sect_id = #{sectId}

/** UsptEvlTargetDao.selectListBySectCount */ select count(a.evl_plan_id) as cnt from uspt_evl_plan a /*평가계획*/ inner join uspt_evl_step b /*평가단계*/ on a.evl_plan_id = b.evl_plan_id and b.sort_ordr_no = 1 /*평가단계의 첫번째 것으로만 join*/ inner join uspt_sect c /*평가분과*/ on a.evl_plan_id = c.evl_plan_id inner join uspt_evl_trget d /*평가대상*/ on b.evl_step_id = d.evl_step_id and c.sect_id = d.sect_id where 1 = 1
and a.evl_plan_id = #{evlPlanId}
and c.sect_id = #{sectId}
and d.evl_trget_id = #{evlTrgetId}

mapper.insert:
/** UsptEvlTrgetDao.insert */
insert into uspt_evl_trget (
	   evl_trget_id
	 , apply_id
	 , sect_id
	 , evl_step_id
	 , presnatn_process_div_cd
	 , presentn_dt
	 , slctn
	 , slctn_dt
	 , attachment_group_id
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{evlTrgetId}
	 , #{applyId}
	 , #{sectId}
	 , #{evlStepId}
	 , #{presnatnProcessDivCd}
	 , #{presentnDt}
	 , #{slctn}
	 , #{slctnDt}
	 , #{attachmentGroupId}
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.delete:
		/** UsptEvlTrgetDao.delete */
		delete from uspt_evl_trget
 			  where evl_trget_id = #{evlTrgetId}

/** UsptEvlTrgetDao.deleteBySectId */
delete
  from uspt_evl_trget
 where sect_id = #{sectId}

mapper.update:
/** UsptEvlTrgetDao.updateSlctn */
update uspt_evl_trget
set
	slctn			= #{slctn}
	, slctn_dt		= #{slctnDt}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
where
	evl_trget_id	= #{evlTrgetId}

mapper.select:
/*UsptEvlTrgetDao.selectPresnatnTargetListCount*/ select count(a.evl_trget_id) as cnt from uspt_evl_trget a /*평가대상 - 발표자료 대상*/ inner join uspt_bsns_pblanc_applcnt b /*공고신청자*/ on b.apply_id = a.apply_id inner join uspt_bsns_pblanc c /*공고*/ on c.pblanc_id = b.pblanc_id inner join uspt_bsns d /*사업*/ on d.bsns_cd = c.bsns_cd inner join cmmt_member cm on cm.member_id = b.member_id left outer join uspt_bsns_pblanc_apply_task e on e.apply_id = b.apply_id where 1 = 1
and b.member_id = #{memberId} --회원ID
and d.bsns_year = #{bsnsYear} --사업년도
and a.presnatn_process_div_cd = #{presnatnProcessDivCd}
and a.evl_trget_id = #{evlTrgetId} -- 대상id
and c.pblanc_nm like '%' || #{pblancNm} || '%' --공고명
and b.receipt_no = #{receiptNo} --접수번호
and cm.member_nm like '%' || #{memberNm} || '%' -- 회원명
and to_char(a.presentn_dt,'yyyymmdd') >= #{presnatnBgnde}
and to_char(a.presentn_dt,'yyyymmdd') <= #{presnatnEndde}
and e.task_nm_ko like '%' || #{taskNmKo} || '%' --과제명
and b.member_id = #{memberId}
and a.presnatn_process_div_cd is not null

/*UsptEvlTrgetDao.selectPresnatnTargetList*/ select c.pblanc_nm , a.presnatn_process_div_cd -- 발표자료 처리코드 , coalesce(public.fn_cmm_get_code_nm('PRESNATN_PROCESS_DIV',a.presnatn_process_div_cd), '미진행') as presnatn_process_div_nm -- 발표자료 처리구분명 , b.receipt_no --접수번호 , b.member_id --회원id , cm.member_nm --회원명 , c.pblanc_nm --공고명 , case when c.ordtm_rcrit = true then '상시모집' else '정시모집' end as ordtm_rcrit_nm --상시모집여부명 , b.rcept_odr --접수차수 , case when a.presentn_dt is null then '-' end as fmt_presentn_dt --제출일 , d.bsns_year , d.bsns_nm --사업명 , cm.enc_mobile_no , a.evl_trget_id , e.task_nm_ko , a.attachment_group_id /*첨부파일그룹ID*/ , ( select presentn_hist_id from ( select row_number() over (order by created_dt desc) as rn, presentn_hist_id from uspt_evl_trget_presentn_hist where presnatn_process_div_cd = '${@aicluster.pms.common.util.Code@splemntRequest}' and evl_trget_id = a.evl_trget_id ) hist where hist.rn = 1 ) as presentn_hist_id --보완요청 최신 이력 ID , row_number() over (order by a.created_dt desc) as rn from uspt_evl_trget a /*평가대상 - 발표자료 대상*/ inner join uspt_bsns_pblanc_applcnt b /*공고신청자*/ on b.apply_id = a.apply_id inner join uspt_bsns_pblanc c /*공고*/ on c.pblanc_id = b.pblanc_id inner join uspt_bsns d /*사업*/ on d.bsns_cd = c.bsns_cd inner join cmmt_member cm on cm.member_id = b.member_id left outer join uspt_bsns_pblanc_apply_task e on e.apply_id = b.apply_id where 1 = 1
and b.member_id = #{memberId} --회원ID
and d.bsns_year = #{bsnsYear} --사업년도
and a.presnatn_process_div_cd = #{presnatnProcessDivCd}
and a.evl_trget_id = #{evlTrgetId} -- 대상id
and c.pblanc_nm like '%' || #{pblancNm} || '%' --공고명
and b.receipt_no = #{receiptNo} --접수번호
and cm.member_nm like '%' || #{memberNm} || '%' -- 회원명
and to_char(a.presentn_dt,'yyyymmdd') >= #{presnatnBgnde}
and to_char(a.presentn_dt,'yyyymmdd') <= #{presnatnEndde}
and e.task_nm_ko like '%' || #{taskNmKo} || '%' --과제명
and b.member_id = #{memberId}
and a.presnatn_process_div_cd is not null
offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.update:
/** UsptEvlTrgetDao.updatePresnatnSttus */
update uspt_evl_trget
   set presnatn_process_div_cd  = #{presnatnProcessDivCd}

   		, attachment_group_id     = #{attachmentGroupId}

	 , updater_id   = #{updaterId}
	 , updated_dt   = #{updatedDt}
where evl_trget_id 	= #{evlTrgetId}

mapper.select:
/** UsptEvlTrgetDao.selectFrontEvlResultListCount */ select count(*) from ( select ulst.last_slctn_trget_id as evl_trget_id from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpr.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id inner join uspt_evl_plan uep on uep.pblanc_id = ubpr.pblanc_id and uep.rcept_odr = ubpr.rcept_odr inner join uspt_evl_last_slctn uels on uels.evl_plan_id = uep.evl_plan_id inner join uspt_last_slctn_trget ulst on ulst.evl_last_slctn_id = uels.evl_last_slctn_id and ulst.apply_id = ubpa.apply_id left outer join uspt_last_slctn_objc_reqst ulsor on ulsor.last_slctn_trget_id = ulst.last_slctn_trget_id where ubpa.member_id = #{memberId}
and ulst.updated_dt >= to_date(#{slctnBgnde}, 'yyyymmdd')
and ulst.updated_dt <= to_date(#{slctnEndde}, 'yyyymmdd')
and ulst.slctn = true and ulst.slctn = false
and ubp.pblanc_nm like concat('%', #{keyword}, '%')
and ubpat.task_nm_ko like concat('%', #{keyword}, '%')
union all select uet.evl_trget_id from uspt_bsns_pblanc_applcnt ubpa inner join uspt_bsns_pblanc_apply_task ubpat on ubpat.apply_id = ubpa.apply_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubpa.pblanc_id and ubpr.rcept_odr = ubpr.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id inner join uspt_evl_plan uep on uep.pblanc_id = ubpr.pblanc_id and uep.rcept_odr = ubpr.rcept_odr and uep.evl_sttus_cd = '${@aicluster.pms.common.util.Code@EVL_STTUS_03_CODE}' inner join uspt_evl_step ues on ues.evl_plan_id = uep.evl_plan_id and ues.evl_step_sttus_cd = '${@aicluster.pms.common.util.Code@EVL_STEP_03_CODE}' inner join uspt_sect us on us.evl_plan_id = uep.evl_plan_id inner join uspt_evl_trget uet on uet.evl_step_id = ues.evl_step_id and uet.sect_id = us.sect_id and uet.apply_id = ubpa.apply_id left outer join uspt_evl_slctn_objc_reqst uesor on uesor.evl_trget_id = uet.evl_trget_id where ubpa.member_id = #{memberId}
and uet.slctn_dt >= to_date(#{slctnBgnde}, 'yyyymmdd')
and uet.slctn_dt <= to_date(#{slctnEndde}, 'yyyymmdd')
and uet.slctn = true and uet.slctn = false
and ubp.pblanc_nm like concat('%', #{keyword}, '%')
and ubpat.task_nm_ko like concat('%', #{keyword}, '%')
) sub
